fn main() {
    let vec0 = vec![22, 44, 66];

    let mut vec1 = fill_vec(vec0);

    println!("{} has length {} with contents {:?}", "vec1", vec1.len(), vec1);

    vec1.push(88);

    println!("{} now has length {} with contents {:?}", "vec1", vec1.len(), vec1);
}

fn fill_vec(mut vec: Vec<i32>) -> Vec<i32> {
    vec.push(77);
    vec
}
